// fetchLatestSQL is the batched newest-row-per-key point lookup shared
// by the cache fetcher and GetFetch.
func (inst *ProvenanceStore) fetchLatestSQL(keys []uint64) string {
	var sb strings.Builder
	sb.WriteString("SELECT * FROM ")
	sb.WriteString(ProvenanceTableName)
	sb.WriteString(" WHERE " + ProvenanceColKey + " IN (")
	for i, k := range keys {
		if i > 0 {
			sb.WriteByte(',')
		}
		sb.WriteString(provenanceKeyLiteral(k))
	}
	sb.WriteString(") ORDER BY " + ProvenanceColOrder + " DESC LIMIT 1 BY " + ProvenanceColKey)
	sb.WriteString(provenanceArrowOutputSettings)
	return sb.String()
}

